  }

  private buildKeysetFilter(
    sortFields: { field: string; dir: 'asc' | 'desc' }[],
    cursorObj: Record<string, any>,
    idField: string,
  ): any {
    const chain = sortFields.some((f) => f.field === idField)
      ? sortFields
      : [...sortFields, { field: idField, dir: 'asc' as const }];

    const idValue = this.dbAdapter.checkId(cursorObj[idField]);
    const valueFor = (field: string) =>
      field === idField ? idValue : cursorObj[field];

    const or = [];
    for (let i = 0; i < chain.length; i++) {
      const and = [];
      for (let j = 0; j < i; j++) {
