      }
      const current = chain[i];
      const op = current.dir === 'desc' ? '$lt' : '$gt';
      and.push({ [current.field]: { [op]: valueFor(current.field) } });
      or.push(and.length > 1 ? { $and: and } : and[0]);
    }
    return { $or: or };
  }

