      obj[f.field] = lastItem[f.field];
    }
    obj[idField] = lastItem[idField];
    obj.__sort = sortFields.map((f) => `${f.field}:${f.dir}`).join(',');
    return Buffer.from(JSON.stringify(obj)).toString('base64');
  }

